// Helper function that creates the body of a request.
function buildBody(queryParam, fieldValue, scoring) {
  return {
    query: {
      bool: {
        must: [
          {
            multi_match: {
              query: queryParam, // Search for this text in all fields.
              fields: ["title", "description"],
              fuzziness: 2,
            },
          },

          { match: { "published-date": fieldValue } }, // Search for this date.
          { match_phrase: { status: "active" } }, // Only include published items.
        ],
      },
    },

    size: 10,

    sort: [{ title: "desc" }], // Sort results by title descending.

    script_fields: {},
  };
}

// Helper function that adds user defined logic to the body of a request using a custom scoring script.
function addScoring(body, scoring) {
  var fields = [];

  for (let key in scoring) {
    // For each field provided by the user...
    if (!fields.includes(key)) {
      let value = {
        script: {},
      };

      Object.keys(scoring[key]).forEach((element) => {
        switch (element) {
          case "weight":
            value["weight"] = scoring[key][element]; // Weight this field in the score calculation.
            break;

          default:
            console.log("No such field in script_score", element);
            return;
        }
      });

      fields.push(value);
    }
  }

  body["script_fields"] = {
    [Object.keys(body)["sort"][0].title]: fields, // Use the scoring logic to rank results by title.
  };
}

// Helper function that requests the Elasticsearch server and outputs the JSON results.
function requestResults(body) {
  let url = process.env["ELASTICSEARCH_URL"] + ":9201";

  var options = {
    method: "POST", // Use a POST request to send the body of this request.
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      Authorization: process.env["ELASTICSEARCH_AUTH"],
    },

    url: `${url}/document-index/_search`,
    json: true, // Parse JSON response to javascript objects.

    body: body,
  };

  request(options, function (error, response, data) {
    console.log(response);
    if (!error && response.statusCode === 200) {
      var results = [];

      for (let result in data["hits"]["hits"]) {
        let jsonResult = JSON.stringify(
          data["hits"]["hits"][result],
          undefined,
          1 // Format output to human readable format with 1 level of indentation.
        );

        results += jsonResult + "\n\n";
      }

      console.log("Results: \n" + results);
    } else {
      if (error) return console.log(error);
      console.log(response["body"]["message"]); // Log error from response message body.
    }
  });
}

